/**
 * Generated by `createschema miniapp.B2BAppMeterIntegrationConfig 'validateMeterReadingUrl:Url;'`
 */

const { faker } = require('@faker-js/faker')

const { makeLoggedInAdminClient, makeClient, expectValuesOfCommonFields } = require('@open-condo/keystone/test.utils')
const {
    expectToThrowAuthenticationErrorToObj, expectToThrowAuthenticationErrorToObjects,
    expectToThrowAccessDeniedErrorToObj,
} = require('@open-condo/keystone/test.utils')

const { B2BAppMeterIntegrationConfig, createTestB2BAppMeterIntegrationConfig, updateTestB2BAppMeterIntegrationConfig } = require('@condo/domains/miniapp/utils/testSchema')
const { makeClientWithNewRegisteredAndLoggedInUser, makeClientWithSupportUser } = require('@condo/domains/user/utils/testSchema')


describe('B2BAppMeterIntegrationConfig', () => {
    describe('CRUD tests', () => {
        let admin
        let support
        let user
        let anonymous

        beforeAll(async () => {
            admin = await makeLoggedInAdminClient()
            support = await makeClientWithSupportUser()
            user = await makeClientWithNewRegisteredAndLoggedInUser()
            anonymous = await makeClient()
        })

        describe('create', () => {
            const createPayload = {
                validateMeterReadingUrl: faker.internet.url(),
            }

            test('admin can', async () => {
                const [obj, attrs] = await createTestB2BAppMeterIntegrationConfig(admin, createPayload)

                expectValuesOfCommonFields(obj, attrs, admin)
                expect(obj).toEqual(expect.objectContaining(createPayload))
            })

            test('support can', async () => {
                const [obj, attrs] = await createTestB2BAppMeterIntegrationConfig(support, createPayload)

                expectValuesOfCommonFields(obj, attrs, support)
                expect(obj).toEqual(expect.objectContaining(createPayload))
            })

            test('user can\'t', async () => {
                await expectToThrowAccessDeniedErrorToObj(async () => {
                    await createTestB2BAppMeterIntegrationConfig(user, createPayload)
                })
            })

            test('anonymous can\'t', async () => {
                await expectToThrowAuthenticationErrorToObj(async () => {
                    await createTestB2BAppMeterIntegrationConfig(anonymous, createPayload)
                })
            })
        })

        describe('update', () => {
            let createdB2BAppMeterIntegrationConfig
            const updatePayload = {
                validateMeterReadingUrl: faker.internet.url(),
            }

            beforeEach(async () => {
                [createdB2BAppMeterIntegrationConfig] = await createTestB2BAppMeterIntegrationConfig(admin)
            })

            test('admin can', async () => {
                const [obj] = await updateTestB2BAppMeterIntegrationConfig(admin, createdB2BAppMeterIntegrationConfig.id, updatePayload)

                expect(obj.v).toEqual(2)
                expect(obj).toEqual(expect.objectContaining(updatePayload))
            })

            test('support can', async () => {
                const [obj] = await updateTestB2BAppMeterIntegrationConfig(support, createdB2BAppMeterIntegrationConfig.id, updatePayload)

                expect(obj.v).toEqual(2)
                expect(obj).toEqual(expect.objectContaining(updatePayload))
            })

            test('user can\'t', async () => {
                await expectToThrowAccessDeniedErrorToObj(async () => {
                    await updateTestB2BAppMeterIntegrationConfig(user, createdB2BAppMeterIntegrationConfig.id, updatePayload)
                })
            })

            test('anonymous can\'t', async () => {
                await expectToThrowAuthenticationErrorToObj(async () => {
                    await updateTestB2BAppMeterIntegrationConfig(anonymous, createdB2BAppMeterIntegrationConfig.id, updatePayload)
                })
            })
        })

        describe('hard delete', () => {
            let createdB2BAppMeterIntegrationConfig

            beforeAll(async () => {
                [createdB2BAppMeterIntegrationConfig] = await createTestB2BAppMeterIntegrationConfig(admin)
            })

            test('nobody can', async () => {
                await expectToThrowAccessDeniedErrorToObj(async () => {
                    await B2BAppMeterIntegrationConfig.delete(admin, createdB2BAppMeterIntegrationConfig.id)
                })
                await expectToThrowAccessDeniedErrorToObj(async () => {
                    await B2BAppMeterIntegrationConfig.delete(support, createdB2BAppMeterIntegrationConfig.id)
                })
                await expectToThrowAccessDeniedErrorToObj(async () => {
                    await B2BAppMeterIntegrationConfig.delete(user, createdB2BAppMeterIntegrationConfig.id)
                })
                await expectToThrowAccessDeniedErrorToObj(async () => {
                    await B2BAppMeterIntegrationConfig.delete(anonymous, createdB2BAppMeterIntegrationConfig.id)
                })
            })
        })

        describe('read', () => {
            let createdB2BAppMeterIntegrationConfig

            beforeAll(async () => {
                [createdB2BAppMeterIntegrationConfig] = await createTestB2BAppMeterIntegrationConfig(admin)
            })

            test('admin can', async () => {
                const apps = await B2BAppMeterIntegrationConfig.getAll(admin, {
                    id: createdB2BAppMeterIntegrationConfig.id,
                })

                expect(apps).toBeDefined()
                expect(apps).toHaveLength(1)
                expect(apps[0]).toHaveProperty('id', createdB2BAppMeterIntegrationConfig.id)
                expect(apps[0]).toHaveProperty('validateMeterReadingUrl', createdB2BAppMeterIntegrationConfig.validateMeterReadingUrl)
            })

            test('support can', async () => {
                const apps = await B2BAppMeterIntegrationConfig.getAll(support, {
                    id: createdB2BAppMeterIntegrationConfig.id,
                })

                expect(apps).toBeDefined()
                expect(apps).toHaveLength(1)
                expect(apps[0]).toHaveProperty('id', createdB2BAppMeterIntegrationConfig.id)
                expect(apps[0]).toHaveProperty('validateMeterReadingUrl', createdB2BAppMeterIntegrationConfig.validateMeterReadingUrl)
            })

            test('user can', async () => {
                const apps = await B2BAppMeterIntegrationConfig.getAll(user, {
                    id: createdB2BAppMeterIntegrationConfig.id,
                })

                expect(apps).toBeDefined()
                expect(apps).toHaveLength(1)
                expect(apps[0]).toHaveProperty('id', createdB2BAppMeterIntegrationConfig.id)
                expect(apps[0]).toHaveProperty('validateMeterReadingUrl', createdB2BAppMeterIntegrationConfig.validateMeterReadingUrl)
            })

            test('anonymous can\'t', async () => {
                await expectToThrowAuthenticationErrorToObjects(async () => {
                    await B2BAppMeterIntegrationConfig.getAll(anonymous, {
                        id: createdB2BAppMeterIntegrationConfig.id,
                    })
                })
            })
        })
    })
})
